import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export type Platform = 'TikTok' | 'Instagram' | 'YouTube';

export type CreatorType = 
  | 'Personal Brand' 
  | 'Business' 
  | 'Coach' 
  | 'Influencer' 
  | 'Faceless Channel';

export type Niche = 
  | 'AI' 
  | 'Finance' 
  | 'Fitness' 
  | 'Motivation' 
  | 'Education' 
  | 'Ecommerce'
  | 'Tech'
  | 'Lifestyle';

export interface UserProfile {
  name: string;
  platforms: Platform[];
  creatorType: CreatorType;
  niche: Niche[];
}

export interface VideoIdea {
  id: string;
  title: string;
  hook: string;
  viralityScore: number;
  script?: string;
  status: 'idea' | 'scripted' | 'generating' | 'ready' | 'scheduled' | 'posted';
  scheduledAt?: string;
}

export interface Metric {
  label: string;
  value: string;
  trend: number;
}

import { GoogleGenAI, Type } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const generateHooks = async (topic: string, niche: string) => {
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Generate 3 viral short-form video hooks for the topic: "${topic}" in the ${niche} niche. 
               Return a JSON array of objects with "text", "type" (e.g., 'Curiosity', 'Scroll-stopping', 'Emotional'), and "viralityScore" (0-100).`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            text: { type: Type.STRING },
            type: { type: Type.STRING },
            viralityScore: { type: Type.NUMBER }
          },
          required: ["text", "type", "viralityScore"]
        }
      }
    }
  });
  return JSON.parse(response.text);
};

export const generateScript = async (hook: string, topic: string) => {
  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: `Write a high-retention short-form video script starting with this hook: "${hook}". 
               The topic is "${topic}". Include timestamps (e.g., [00:03]). Structure it as Hook, Core Message, and CTA.`,
    config: {
      systemInstruction: "You are a world-class viral video content strategist."
    }
  });
  return response.text;
};

export const getCoachAdvice = async (history: string[], question: string) => {
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Based on this video performance history: ${history.join(', ')}. Answer this creator question: "${question}"`,
    config: {
      systemInstruction: "You are 'AutoCreator AI Coach', a direct, data-driven, and encouraging social media growth expert."
    }
  });
  return response.text;
};

