        <nav className="flex-1 space-y-1">
          <SidebarItem icon={LayoutDashboard} label="Dashboard" active={currentView === 'dashboard'} onClick={() => setCurrentView('dashboard')} />
          <SidebarItem icon={Sparkles} label="Hook Generator" active={currentView === 'hooks'} onClick={() => setCurrentView('hooks')} />
          <SidebarItem icon={PenTool} label="Script Builder" active={currentView === 'scripts'} onClick={() => setCurrentView('scripts')} />
          <SidebarItem icon={Video} label="Video Generator" active={currentView === 'generator'} onClick={() => setCurrentView('generator')} />
          <SidebarItem icon={Calendar} label="Scheduler" active={currentView === 'scheduler'} onClick={() => setCurrentView('scheduler')} />
          <SidebarItem icon={BarChart3} label="Analytics" active={currentView === 'analytics'} onClick={() => setCurrentView('analytics')} />
