  return (
    <div className="min-h-screen bg-[#0A0A0B] flex items-center justify-center p-6">
      <div className="w-full max-w-lg">
        {step === 0 && (
          <div className="text-center space-y-6 animate-in fade-in duration-700">
            <div className="inline-block bg-purple-600 p-4 rounded-3xl shadow-2xl shadow-purple-600/20 mb-4 transform hover:rotate-12 transition-transform cursor-pointer">
              <Zap size={64} className="text-white fill-white" />
            </div>
            <h1 className="text-5xl font-black tracking-tight leading-tight">
              Create viral short-form <br/> <span className="text-purple-500">automatically.</span>
            </h1>
            <p className="text-zinc-400 text-lg max-w-md mx-auto">
              Scripts. Hooks. Captions. Videos. Done. Let AI handle the heavy lifting while you focus on the vision.
            </p>
            <button 
              onClick={onNext}
              className="mt-8 px-12 py-4 bg-purple-600 hover:bg-purple-500 text-white rounded-2xl font-bold text-xl transition-all shadow-xl shadow-purple-600/20 active:scale-95"
            >
              Start Creating
            </button>
          </div>
        )}

        {step === 1 && (
          <div className="space-y-8 animate-in slide-in-from-right duration-500">
            <div className="space-y-2">
              <h2 className="text-3xl font-bold">What's your name?</h2>
              <p className="text-zinc-500">We'll use this to personalize your dashboard.</p>
            </div>
            <input 
              type="text" 
              className="w-full bg-[#151518] border border-[#26262B] p-4 rounded-2xl text-xl focus:outline-none focus:border-purple-500"
              placeholder="Enter your name"
              value={form.name}
              onChange={(e) => setForm({...form, name: e.target.value})}
            />
            <button 
              disabled={!form.name}
              onClick={onNext}
              className="w-full py-4 bg-purple-600 hover:bg-purple-500 disabled:opacity-50 disabled:cursor-not-allowed text-white rounded-2xl font-bold text-lg transition-all"
            >
              Continue
            </button>
          </div>
        )}

        {step === 2 && (
          <div className="space-y-8 animate-in slide-in-from-right duration-500">
            <div className="space-y-2">
              <h2 className="text-3xl font-bold">Pick your platforms</h2>
              <p className="text-zinc-500">Where are you looking to go viral?</p>
            </div>
            <div className="grid grid-cols-1 gap-4">
              {['TikTok', 'Instagram', 'YouTube'].map((p) => (
                <button
                  key={p}
                  onClick={() => {
                    const next = form.platforms.includes(p as Platform) 
                      ? form.platforms.filter(x => x !== p)
                      : [...form.platforms, p as Platform];
                    setForm({...form, platforms: next});
                  }}
                  className={`flex items-center justify-between p-6 rounded-2xl border transition-all ${
                    form.platforms.includes(p as Platform) 
                      ? 'bg-purple-600/20 border-purple-500 text-white' 
                      : 'bg-[#151518] border-[#26262B] text-zinc-400'
                  }`}
                >
                  <div className="flex items-center gap-4">
                    {p === 'TikTok' && <Smartphone size={24} />}
                    {p === 'Instagram' && <Instagram size={24} />}
                    {p === 'YouTube' && <Youtube size={24} />}
                    <span className="font-bold text-lg">{p}</span>
                  </div>
                  {form.platforms.includes(p as Platform) && <CheckCircle2 size={24} />}
                </button>
              ))}
            </div>
            <button 
              disabled={form.platforms.length === 0}
              onClick={onNext}
              className="w-full py-4 bg-purple-600 hover:bg-purple-500 disabled:opacity-50 text-white rounded-2xl font-bold text-lg transition-all"
