            </div>
            <div className="flex flex-wrap gap-3">
              {niches.map((n) => (
                <button
                  key={n}
                  onClick={() => {
                    const next = form.niche.includes(n) 
                      ? form.niche.filter(x => x !== n)
                      : [...form.niche, n].slice(-3);
                    setForm({...form, niche: next});
                  }}
                  className={`px-6 py-3 rounded-full border transition-all font-semibold ${
                    form.niche.includes(n) 
                      ? 'bg-purple-500 border-purple-500 text-white shadow-lg shadow-purple-500/20' 
                      : 'bg-[#151518] border-[#26262B] text-zinc-400'
                  }`}
                >
