              ))}
            </div>
            <button 
              onClick={() => onComplete(form)}
              className="w-full py-4 bg-purple-600 hover:bg-purple-500 text-white rounded-2xl font-bold text-lg transition-all shadow-xl shadow-purple-600/20"
            >
              Get Started
            </button>
          </div>
        )}
      </div>
    </div>
  );
}

