          <button 
            onClick={handleGenerate}
            disabled={loading}
            className="m-2 px-8 bg-purple-600 hover:bg-purple-500 disabled:bg-zinc-800 disabled:text-zinc-500 text-white rounded-xl font-bold flex items-center gap-2 transition-all"
