function CoachView() {
  const [messages, setMessages] = useState([
    { role: 'coach', text: "Hello! I'm your AI Content Coach. I've analyzed your last 5 videos and noticed your retention drops at the 30-second mark. How can I help you improve today?" }
  ]);
  const [input, setInput] = useState('');

  const handleSend = () => {
    if (!input) return;
    setMessages(prev => [...prev, { role: 'user', text: input }]);
    // Simulate AI response
    setTimeout(() => {
      setMessages(prev => [...prev, { role: 'coach', text: "Based on trending data in your niche (AI & Tech), I recommend trying a 'comparison' style video next. Show your viewers the difference between two tools. This format usually gets 40% higher share rates." }]);
    }, 1000);
    setInput('');
  };

  return (
    <div className="h-[calc(100vh-160px)] flex flex-col max-w-5xl mx-auto">
      <div className="flex-1 overflow-y-auto space-y-6 pr-4">
        {messages.map((m, i) => (
          <div key={i} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'}`}>
