function HookGeneratorView() {
  const [topic, setTopic] = useState('');
  const [loading, setLoading] = useState(false);
  const [hooks, setHooks] = useState<any[]>([]);

  const handleGenerate = async () => {
    if (!topic) return;
    setLoading(true);
    try {
      const results = await generateHooks(topic, "general");
      setHooks(results);
    } catch (e) {
      console.error(e);
    } finally {
      setLoading(false);
