function CoachView() {
  const [mode, setMode] = useState<'chat' | 'voice'>('chat');
  const [messages, setMessages] = useState([{ role: 'coach', text: "Hello! I'm your AI Growth Coach. Want to chat about strategy or try our new real-time Voice Mode?", thinking: "" }]);
  const [input, setInput] = useState('');
  const [isThinking, setIsThinking] = useState(false);

  // Audio state
  const [isListening, setIsListening] = useState(false);
  const audioContextRef = useRef<AudioContext | null>(null);
  const sessionRef = useRef<any>(null);
  const nextStartTimeRef = useRef(0);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());

  const handleSendChat = async () => {
    if (!input) return;
    const userMsg = input;
    setMessages(prev => [...prev, { role: 'user', text: userMsg, thinking: "" }]);
    setInput('');
    setIsThinking(true);

    try {
      const response = await complexCoachAdvice([], userMsg);
      setMessages(prev => [...prev, { role: 'coach', text: response, thinking: "" }]);
    } catch (e) {
      setMessages(prev => [...prev, { role: 'coach', text: "Sorry, I had trouble thinking about that.", thinking: "" }]);
    } finally {
      setIsThinking(false);
    }
  };

  const startVoice = async () => {
    setIsListening(true);
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

    audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
    const outputContext = audioContextRef.current;
    const inputContext = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
    const stream = await navigator.mediaDevices.getUserMedia({ audio: true });

    const sessionPromise = ai.live.connect({
      model: 'gemini-2.5-flash-native-audio-preview-09-2025',
      callbacks: {
        onopen: () => {
          const source = inputContext.createMediaStreamSource(stream);
          const processor = inputContext.createScriptProcessor(4096, 1, 1);
          processor.onaudioprocess = (e) => {
            const data = e.inputBuffer.getChannelData(0);
            const int16 = new Int16Array(data.length);
            for (let i = 0; i < data.length; i++) int16[i] = data[i] * 32768;
            sessionPromise.then(s => s.sendRealtimeInput({ media: { data: encode(new Uint8Array(int16.buffer)), mimeType: 'audio/pcm;rate=16000' } }));
          };
          source.connect(processor);
          processor.connect(inputContext.destination);
        },
        onmessage: async (msg: LiveServerMessage) => {
          const audioBase64 = msg.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
          if (audioBase64) {
            nextStartTimeRef.current = Math.max(nextStartTimeRef.current, outputContext.currentTime);
            const buffer = await decodeAudioData(decode(audioBase64), outputContext, 24000, 1);
            const source = outputContext.createBufferSource();
            source.buffer = buffer;
            source.connect(outputContext.destination);
            source.start(nextStartTimeRef.current);
            nextStartTimeRef.current += buffer.duration;
            sourcesRef.current.add(source);
          }
        },
        onclose: () => setIsListening(false),
        onerror: () => setIsListening(false)
      },
      config: { responseModalities: [Modality.AUDIO], speechConfig: { voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Zephyr' } } } }
    });
    sessionRef.current = await sessionPromise;
  };

  const stopVoice = () => {
    if (sessionRef.current) sessionRef.current.close();
    setIsListening(false);
  };

  return (
    <div className="flex flex-col h-[700px] max-w-4xl mx-auto">
      <div className="flex justify-between items-center mb-6">
        <div className="flex gap-2 p-1 bg-zinc-900 rounded-xl">
          <button onClick={() => setMode('chat')} className={`px-4 py-1.5 rounded-lg text-sm font-bold ${mode === 'chat' ? 'bg-zinc-800 text-white' : 'text-zinc-500'}`}>Chat Mode</button>
          <button onClick={() => setMode('voice')} className={`px-4 py-1.5 rounded-lg text-sm font-bold ${mode === 'voice' ? 'bg-zinc-800 text-white' : 'text-zinc-500'}`}>Live Voice</button>
        </div>
        {mode === 'chat' && isThinking && <div className="flex items-center gap-2 text-purple-400 text-xs font-bold animate-pulse"><BrainCircuit size={16} /> THINKING MODE ACTIVE</div>}
      </div>

      {mode === 'chat' ? (
        <div className="flex-1 flex flex-col">
          <div className="flex-1 overflow-y-auto space-y-4 pr-4 mb-6">
            {messages.map((m, i) => (
              <div key={i} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                <div className={`max-w-[80%] p-4 rounded-2xl ${m.role === 'user' ? 'bg-purple-600 text-white rounded-tr-none' : 'bg-zinc-900 border border-zinc-800 rounded-tl-none'}`}>
                  <p className="text-sm leading-relaxed">{m.text}</p>
                </div>
              </div>
            ))}
            {isThinking && <div className="p-4 bg-purple-900/10 border border-purple-500/20 rounded-2xl w-[80%]"><RefreshCw size={16} className="animate-spin text-purple-500" /></div>}
          </div>
          <div className="flex gap-2">
            <input type="text" placeholder="Ask about your content strategy..." className="flex-1 bg-zinc-900 border border-zinc-800 p-4 rounded-2xl" value={input} onChange={e => setInput(e.target.value)} onKeyDown={e => e.key === 'Enter' && handleSendChat()} />
            <button onClick={handleSendChat} className="p-4 bg-purple-600 rounded-2xl"><ChevronRight /></button>
          </div>
        </div>
      ) : (
        <div className="flex-1 flex flex-col items-center justify-center space-y-8">
          <div className={`w-48 h-48 rounded-full border-4 flex items-center justify-center transition-all ${isListening ? 'border-purple-500 scale-110 shadow-[0_0_50px_rgba(168,85,247,0.4)] animate-pulse' : 'border-zinc-800 scale-100'}`}>
            <Mic size={64} className={isListening ? 'text-purple-400' : 'text-zinc-700'} />
          </div>
          <div className="text-center space-y-2">
            <h3 className="text-2xl font-bold">{isListening ? 'Listening...' : 'Ready to Talk?'}</h3>
            <p className="text-zinc-500">Live Voice uses Gemini 2.5 Native Audio for real-time conversation.</p>
          </div>
          <button onClick={isListening ? stopVoice : startVoice} className={`px-12 py-4 rounded-full font-bold text-lg flex items-center gap-3 transition-all ${isListening ? 'bg-rose-600' : 'bg-purple-600'}`}>
            {isListening ? <><StopCircle /> Stop Session</> : <><Mic /> Start Conversation</>}
          </button>
        </div>
      )}
    </div>
  );
}

