          <button onClick={() => setActiveTab('edit')} className={`px-6 py-2 rounded-xl text-sm font-bold transition-all ${activeTab === 'edit' ? 'bg-purple-600 text-white' : 'text-zinc-500'}`}>Edit Frame</button>
        </div>

        {activeTab === 'visuals' && (
          <div className="space-y-6 animate-in fade-in duration-300">
            <h3 className="text-xl font-bold">Image Asset Generator (Pro)</h3>
            <textarea placeholder="Describe the scene..." className="w-full bg-[#151518] border border-[#26262B] p-4 rounded-2xl h-32 focus:outline-none focus:border-purple-500" value={imagePrompt} onChange={e => setImagePrompt(e.target.value)} />
            <div className="grid grid-cols-2 gap-4">
              <div className="space-y-2"><p className="text-xs font-bold text-zinc-500">ASPECT RATIO</p>
                <select className="w-full bg-zinc-800 border border-zinc-700 rounded-xl p-2" value={aspectRatio} onChange={e => setAspectRatio(e.target.value)}>
                  {['1:1', '9:16', '16:9', '4:3', '3:4'].map(r => <option key={r} value={r}>{r}</option>)}
                </select>
              </div>
              <div className="space-y-2"><p className="text-xs font-bold text-zinc-500">QUALITY</p>
                <select className="w-full bg-zinc-800 border border-zinc-700 rounded-xl p-2" value={size} onChange={e => setSize(e.target.value)}>
                  {['1K', '2K', '4K'].map(s => <option key={s} value={s}>{s}</option>)}
                </select>
              </div>
            </div>
            <button onClick={handleGenImage} disabled={loading} className="w-full py-4 bg-purple-600 rounded-2xl font-bold hover:bg-purple-500 flex items-center justify-center gap-2 transition-all shadow-xl shadow-purple-600/20">
