function VideoGeneratorView() {
  const [activeTab, setActiveTab] = useState<'visuals' | 'animate' | 'edit'>('visuals');
  const [loading, setLoading] = useState(false);
  const [imagePrompt, setImagePrompt] = useState('');
  const [aspectRatio, setAspectRatio] = useState('9:16');
  const [size, setSize] = useState('1K');
  const [generatedImage, setGeneratedImage] = useState<string | null>(null);
  const [editPrompt, setEditPrompt] = useState('');
  const [veoStatus, setVeoStatus] = useState<'idle' | 'generating' | 'polling' | 'ready'>('idle');
  const [videoUrl, setVideoUrl] = useState<string | null>(null);

  const handleGenImage = async () => {
    // Check for API key since it uses a pro model
    if (!window.aistudio.hasSelectedApiKey()) {
      await window.aistudio.openSelectKey();
    }
    setLoading(true);
    try {
      const img = await generateProImage(imagePrompt, aspectRatio, size);
      setGeneratedImage(img);
    } catch (e) { alert("Failed to generate image."); } finally { setLoading(false); }
  };

  const handleEditImage = async () => {
    if (!generatedImage) return;
    setLoading(true);
    try {
      const img = await editImageWithFlash(generatedImage, editPrompt);
      if (img) setGeneratedImage(img);
    } catch (e) { alert("Edit failed."); } finally { setLoading(false); }
  };

  const handleGenerateVeo = async () => {
    if (!window.aistudio.hasSelectedApiKey()) {
      await window.aistudio.openSelectKey();
    }
    setVeoStatus('generating');
    try {
      // Re-initialize GoogleGenAI to ensure the latest key is used
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      let op = await ai.models.generateVideos({
        model: 'veo-3.1-fast-generate-preview',
        image: generatedImage ? { imageBytes: generatedImage.split(',')[1], mimeType: 'image/png' } : undefined,
        prompt: imagePrompt || "Cinematic movement",
        config: { numberOfVideos: 1, resolution: '720p', aspectRatio: (aspectRatio === '9:16' ? '9:16' : '16:9') }
      });

      setVeoStatus('polling');
      while (!op.done) {
        await new Promise(r => setTimeout(r, 10000));
        op = await ai.operations.getVideosOperation({ operation: op });
      }

      const link = op.response?.generatedVideos?.[0]?.video?.uri;
      if (link) {
        const res = await fetch(`${link}&key=${process.env.API_KEY}`);
        const blob = await res.blob();
        setVideoUrl(URL.createObjectURL(blob));
        setVeoStatus('ready');
      }
    } catch (e) { setVeoStatus('idle'); alert("Veo failed: " + (e as any).message); }
  };

  return (
    <div className="grid lg:grid-cols-2 gap-12">
      <div className="space-y-8">
        <div className="flex gap-4 p-1 bg-zinc-900 rounded-2xl w-fit">
          <button onClick={() => setActiveTab('visuals')} className={`px-6 py-2 rounded-xl text-sm font-bold transition-all ${activeTab === 'visuals' ? 'bg-purple-600 text-white' : 'text-zinc-500'}`}>Create Visuals</button>
          <button onClick={() => setActiveTab('animate')} className={`px-6 py-2 rounded-xl text-sm font-bold transition-all ${activeTab === 'animate' ? 'bg-purple-600 text-white' : 'text-zinc-500'}`}>Animate (Veo)</button>
          <button onClick={() => setActiveTab('edit')} className={`px-6 py-2 rounded-xl text-sm font-bold transition-all ${activeTab === 'edit' ? 'bg-purple-600 text-white' : 'text-zinc-500'}`}>Edit Frame</button>
        </div>

        {activeTab === 'visuals' && (
