// Hook Generator View - Uses Search Grounding
function HookGeneratorView({ userProfile }: { userProfile: UserProfile | null }) {
  const [topic, setTopic] = useState('');
  const [loading, setLoading] = useState(false);
  const [results, setResults] = useState<any[]>([]);
  const [sources, setSources] = useState<any[]>([]);

  const handleGenerate = async () => {
    if (!topic) return;
    setLoading(true);
    try {
      const niche = userProfile?.niche[0] || 'AI';
      const { results, sources } = await generateHooksWithSearch(topic, niche);
      setResults(results);
      setSources(sources);
    } catch (e) {
      console.error(e);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      <Card className="space-y-4">
        <div className="flex items-center gap-2 mb-2">
          <Globe className="text-purple-400" size={20} />
          <h3 className="text-xl font-bold">Search-Grounded Hooks</h3>
        </div>
        <p className="text-zinc-500 text-sm">We use Google Search to find real-time trends for your topic.</p>
        <div className="flex flex-col sm:flex-row gap-4">
          <input 
            value={topic}
            onChange={(e) => setTopic(e.target.value)}
            placeholder="What's your video about? (e.g. 'Bitcoin 2025 Prediction')" 
            className="flex-1 bg-zinc-900 border border-zinc-800 rounded-xl px-4 py-3 focus:outline-none focus:border-purple-500"
          />
          <button 
            onClick={handleGenerate}
            disabled={loading}
            className="bg-purple-600 hover:bg-purple-500 px-6 py-3 rounded-xl font-bold flex items-center justify-center gap-2 disabled:opacity-50 min-w-[140px]"
          >
            {loading ? <RefreshCw className="animate-spin" size={18} /> : <Wand2 size={18} />}
            Generate
          </button>
        </div>
      </Card>

      <div className="grid md:grid-cols-3 gap-6">
        {results.map((h, i) => (
          <Card key={i} className="space-y-4 border-zinc-800 hover:border-purple-500/30 transition-all">
            <div className="flex justify-between">
              <Badge color="blue">{h.type}</Badge>
              <div className="text-purple-400 font-bold text-xs flex items-center gap-1">
                <TrendingUp size={12} /> {h.viralityScore}%
              </div>
            </div>
            <p className="text-lg font-bold italic text-zinc-200">"{h.text}"</p>
          </Card>
        ))}
      </div>

      {sources.length > 0 && (
        <Card className="space-y-4 border-zinc-800 bg-zinc-900/20">
          <div className="flex items-center gap-2">
            <Search size={16} className="text-zinc-500" />
            <h4 className="text-xs font-bold uppercase tracking-widest text-zinc-500">Sources & Grounding</h4>
          </div>
          <div className="grid sm:grid-cols-2 gap-3">
            {sources.map((s: any, i: number) => (
              <a key={i} href={s.web?.uri} target="_blank" rel="noreferrer" className="flex items-center gap-2 text-xs text-purple-400 hover:text-purple-300 transition-colors truncate">
                <ExternalLink size={12} /> {s.web?.title || s.web?.uri}
              </a>
            ))}
          </div>
        </Card>
      )}
    </div>
  );
}

