// --- Onboarding Logic ---

function Onboarding({ step, initialProfile, onNext, onComplete }: any) {
  const [form, setForm] = useState<UserProfile>(initialProfile || { 
    name: '', 
    platforms: [], 
    creatorType: 'Personal Brand', 
    niche: [] 
  });

  const [loadingStep, setLoadingStep] = useState(0);

  useEffect(() => {
    if (step === 3) { // After platforms
      const timer = setInterval(() => {
        setLoadingStep(prev => {
          if (prev >= 3) {
            clearInterval(timer);
            onNext();
            return 3;
          }
          return prev + 1;
        });
      }, 1200);
      return () => clearInterval(timer);
    }
  }, [step]);

  const platforms: {id: Platform, icon: any, label: string}[] = [
    { id: 'TikTok', icon: Smartphone, label: 'TikTok' },
    { id: 'Instagram', icon: Instagram, label: 'Instagram Reels' },
    { id: 'YouTube', icon: Youtube, label: 'YouTube Shorts' }
  ];

  const niches: Niche[] = ['AI', 'Finance', 'Fitness', 'Motivation', 'Education', 'Ecommerce', 'Tech', 'Lifestyle'];

  const containerClass = "min-h-screen bg-[#0A0A0B] flex items-center justify-center p-6 animate-in fade-in zoom-in duration-500";
  const innerClass = "w-full max-w-xl space-y-8";

  // Step 0: Profile Creation (Name + Platforms)
  if (step === 0) return (
    <div className={containerClass}>
      <div className={innerClass}>
        <div className="space-y-2">
          <Badge color="purple">Profile Setup</Badge>
          <h2 className="text-4xl font-black">Let's build your brand.</h2>
          <p className="text-zinc-500">Pick the platforms you want to dominate.</p>
        </div>
        <div className="grid gap-4">
          {platforms.map(p => (
            <button 
              key={p.id}
              onClick={() => {
                const current = form.platforms;
                const next = current.includes(p.id) ? current.filter(x => x !== p.id) : [...current, p.id];
                setForm({...form, platforms: next});
              }}
              className={`flex items-center justify-between p-6 rounded-3xl border-2 transition-all ${form.platforms.includes(p.id) ? 'border-purple-600 bg-purple-600/10' : 'border-[#26262B] bg-[#151518] hover:border-zinc-700'}`}
            >
              <div className="flex items-center gap-4">
                <p.icon size={24} className={form.platforms.includes(p.id) ? 'text-purple-400' : 'text-zinc-500'} />
                <span className="text-xl font-bold">{p.label}</span>
              </div>
              {form.platforms.includes(p.id) && <CheckCircle2 className="text-purple-500" />}
            </button>
          ))}
        </div>
        <button onClick={onNext} disabled={form.platforms.length === 0} className="w-full py-5 bg-purple-600 disabled:bg-zinc-800 disabled:text-zinc-600 hover:bg-purple-500 text-white font-black text-xl rounded-2xl transition-all shadow-xl shadow-purple-600/20">Continue</button>
      </div>
    </div>
  );

  // Step 1: Niche Selection
  if (step === 1) return (
    <div className={containerClass}>
      <div className={innerClass}>
        <div className="space-y-2">
          <Badge color="purple">Context Discovery</Badge>
          <h2 className="text-4xl font-black">Pick your niche.</h2>
          <p className="text-zinc-500">This helps Gemini optimize your hooks.</p>
        </div>
        <div className="flex flex-wrap gap-3">
          {niches.map(n => (
            <button key={n} onClick={() => {
              const current = form.niche;
              const next = current.includes(n) ? current.filter(x => x !== n) : [...current, n];
              setForm({...form, niche: next});
