              <p className="text-xl font-bold">{c}</p>
            </button>
          ))}
        </div>
      </div>
    </div>
  );

  // Step 3: Processing
  if (step === 3) return (
    <div className={containerClass}>
      <div className="text-center space-y-12 w-full max-sm mx-auto">
        <div className="relative w-24 h-24 mx-auto">
          <div className="absolute inset-0 border-4 border-purple-900 rounded-full"></div>
          <div className="absolute inset-0 border-4 border-purple-500 rounded-full border-t-transparent animate-spin"></div>
          <div className="absolute inset-0 flex items-center justify-center text-purple-500"><Sparkles /></div>
        </div>
        <h2 className="text-2xl font-bold">Scaling your content engine...</h2>
      </div>
    </div>
  );

  // Step 4: Success
  if (step === 4) return (
    <div className={containerClass}>
      <div className={innerClass}>
        <h2 className="text-4xl font-black text-center">Engine Initialized 🚀</h2>
        <Card className="p-8 text-center space-y-4">
