  const [ideas] = useState<VideoIdea[]>([
    { id: '1', title: 'The Future of AI Tools', hook: 'AI is changing everything...', viralityScore: 92, status: 'ready' },
    { id: '2', title: 'Why 90% of Creators Fail', hook: 'Stop posting daily until you see this...', viralityScore: 88, status: 'scripted' },
  ]);

  const handleAuthSuccess = (userData: Partial<UserProfile>) => {
    if (authMode === 'login') {
      // Simulate existing user
      setUserProfile({
        name: userData.name || 'Creator',
        platforms: ['TikTok', 'Instagram'],
        creatorType: 'Personal Brand',
        niche: ['AI']
      });
      setView('app');
      setCurrentSubView('dashboard');
    } else {
      // Signup starts onboarding
      setUserProfile({ name: userData.name || '', platforms: [], creatorType: 'Personal Brand', niche: [] });
      setView('app');
      setOnboardingStep(0);
    }
  };

  const handleLogout = () => {
    setUserProfile(null);
    setView('landing');
    setOnboardingStep(0);
  };

  if (view === 'landing') return <LandingPage onStart={() => { setAuthMode('signup'); setView('auth'); }} onLogin={() => { setAuthMode('login'); setView('auth'); }} />;

  if (view === 'auth') return <AuthView mode={authMode} onSwitch={setAuthMode} onSuccess={handleAuthSuccess} />;

  if (view === 'app' && onboardingStep < 5 && userProfile && userProfile.platforms.length === 0) return (
    <Onboarding 
      step={onboardingStep} 
      initialProfile={userProfile}
      onNext={() => setOnboardingStep(prev => prev + 1)} 
      onComplete={(profile: UserProfile) => { 
        setUserProfile(profile); 
        setOnboardingStep(5); 
