  ]);

  useEffect(() => {
    const unsubscribe = onAuthStateChanged(auth, async (user) => {
      if (user) {
        const profile = await getProfile(user.uid);
        if (profile && profile.platforms.length > 0) {
          setUserProfile(profile);
          setView('app');
          setCurrentSubView('dashboard');
        } else {
          // New user or incomplete profile
          setUserProfile(profile || { name: user.displayName || 'Creator', platforms: [], creatorType: 'Personal Brand', niche: [] });
          setView('app');
          setOnboardingStep(0);
        }
      } else {
        setView('landing');
      }
    });
    return () => unsubscribe();
  }, []);

  const handleAuthSuccess = (user: FirebaseUser) => {
    // onAuthStateChanged takes care of the redirect
  };

  const handleLogout = async () => {
    await logoutUser();
    setUserProfile(null);
    setView('landing');
    setOnboardingStep(0);
  };

  const handleOnboardingComplete = async (profile: UserProfile) => {
    if (auth.currentUser) {
      await saveProfile(auth.currentUser.uid, profile);
      setUserProfile(profile);
      setOnboardingStep(5);
    }
  };

  if (view === 'loading') return (
    <div className="min-h-screen bg-[#0A0A0B] flex items-center justify-center">
       <Loader2 className="animate-spin text-purple-600" size={48} />
    </div>
  );

  if (view === 'landing') return <LandingPage onStart={() => { setAuthMode('signup'); setView('auth'); }} onLogin={() => { setAuthMode('login'); setView('auth'); }} />;

  if (view === 'auth') return <AuthView mode={authMode} onSwitch={setAuthMode} onSuccess={handleAuthSuccess} />;

  if (view === 'app' && onboardingStep < 5 && userProfile && userProfile.platforms.length === 0) return (
    <Onboarding 
      step={onboardingStep} 
      initialProfile={userProfile}
      onNext={() => setOnboardingStep(prev => prev + 1)} 
      onComplete={handleOnboardingComplete} 
    />
  );

  return (
    <div className="flex h-screen bg-[#0A0A0B] text-white overflow-hidden">
      <aside className="w-64 border-r border-[#26262B] flex flex-col p-4 sticky top-0 h-screen bg-[#0A0A0B]">
