// --- Onboarding Logic ---

function Onboarding({ step, initialProfile, onNext, onComplete }: any) {
  const [form, setForm] = useState<UserProfile>(initialProfile || { 
    name: '', 
    platforms: [], 
    creatorType: 'Personal Brand', 
    niche: [],
    plan: 'Starter'
  });

  const [loadingStep, setLoadingStep] = useState(0);

  useEffect(() => {
    if (step === 3) { // After platforms
      const timer = setInterval(() => {
        setLoadingStep(prev => {
          if (prev >= 3) {
            clearInterval(timer);
            onNext();
            return 3;
          }
          return prev + 1;
        });
      }, 1200);
      return () => clearInterval(timer);
    }
  }, [step]);

  const platforms: {id: Platform, icon: any, label: string}[] = [
    { id: 'TikTok', icon: Smartphone, label: 'TikTok' },
    { id: 'Instagram', icon: Instagram, label: 'Instagram Reels' },
    { id: 'YouTube', icon: Youtube, label: 'YouTube Shorts' }
  ];

  const niches: Niche[] = ['AI', 'Finance', 'Fitness', 'Motivation', 'Education', 'Ecommerce', 'Tech', 'Lifestyle'];

  const containerClass = "min-h-screen bg-[#0A0A0B] flex items-center justify-center p-6 animate-in fade-in zoom-in duration-500";
  const innerClass = "w-full max-w-xl space-y-8";

  // Step 0: Profile Creation (Platforms)
  if (step === 0) return (
    <div className={containerClass}>
      <div className={innerClass}>
        <div className="space-y-2">
          <Badge color="purple">Profile Setup</Badge>
          <h2 className="text-4xl font-black">Dominance selection.</h2>
          <p className="text-zinc-500">Pick the platforms where you want to go viral.</p>
        </div>
        <div className="grid gap-4">
          {platforms.map(p => (
            <button 
              key={p.id}
              onClick={() => {
                const current = form.platforms;
                const next = current.includes(p.id) ? current.filter(x => x !== p.id) : [...current, p.id];
                setForm({...form, platforms: next});
              }}
              className={`flex items-center justify-between p-6 rounded-3xl border-2 transition-all ${form.platforms.includes(p.id) ? 'border-purple-600 bg-purple-600/10' : 'border-[#26262B] bg-[#151518] hover:border-zinc-700'}`}
            >
              <div className="flex items-center gap-4">
                <p.icon size={24} className={form.platforms.includes(p.id) ? 'text-purple-400' : 'text-zinc-500'} />
                <span className="text-xl font-bold">{p.label}</span>
              </div>
              {form.platforms.includes(p.id) && <CheckCircle2 className="text-purple-500" />}
            </button>
          ))}
        </div>
        <button onClick={onNext} disabled={form.platforms.length === 0} className="w-full py-5 bg-purple-600 disabled:bg-zinc-800 disabled:text-zinc-600 hover:bg-purple-500 text-white font-black text-xl rounded-2xl transition-all shadow-xl shadow-purple-600/20">Continue</button>
      </div>
    </div>
  );

  // Step 1: Niche Selection
  if (step === 1) return (
    <div className={containerClass}>
      <div className={innerClass}>
        <div className="space-y-2">
          <Badge color="purple">Context Discovery</Badge>
          <h2 className="text-4xl font-black">Pick your niche.</h2>
          <p className="text-zinc-500">This helps Gemini optimize your hooks.</p>
        </div>
        <div className="flex flex-wrap gap-3">
          {niches.map(n => (
            <button key={n} onClick={() => {
              const current = form.niche;
              const next = current.includes(n) ? current.filter(x => x !== n) : [...current, n];
              setForm({...form, niche: next});
            }} className={`px-6 py-3 rounded-full border-2 transition-all font-bold ${form.niche.includes(n) ? 'border-purple-600 bg-purple-600 text-white' : 'border-[#26262B] bg-[#151518] text-zinc-400'}`}>{n}</button>
          ))}
        </div>
        <button onClick={onNext} disabled={form.niche.length === 0} className="w-full py-5 bg-purple-600 disabled:bg-zinc-800 hover:bg-purple-500 text-white font-black text-xl rounded-2xl transition-all">Next</button>
      </div>
    </div>
  );

  // Step 2: Creator Type
  if (step === 2) return (
    <div className={containerClass}>
      <div className={innerClass}>
        <div className="space-y-2">
          <Badge color="purple">Final Step</Badge>
          <h2 className="text-4xl font-black">How do you describe yourself?</h2>
          <p className="text-zinc-500">This tunes the voice of your scripts.</p>
        </div>
        <div className="grid gap-3">
          {['Personal Brand', 'Business', 'Coach', 'Influencer', 'Faceless Channel'].map(c => (
            <button key={c} onClick={() => { setForm({...form, creatorType: c as CreatorType}); onNext(); }} className={`text-left p-6 rounded-3xl border-2 transition-all border-[#26262B] bg-[#151518] hover:border-purple-600`}>
              <p className="text-xl font-bold">{c}</p>
            </button>
          ))}
        </div>
      </div>
    </div>
  );

  // Step 3: Processing
  if (step === 3) return (
    <div className={containerClass}>
      <div className="text-center space-y-12 w-full max-sm mx-auto">
        <div className="relative w-24 h-24 mx-auto">
          <div className="absolute inset-0 border-4 border-purple-900 rounded-full"></div>
          <div className="absolute inset-0 border-4 border-purple-500 rounded-full border-t-transparent animate-spin"></div>
          <div className="absolute inset-0 flex items-center justify-center text-purple-500"><Sparkles /></div>
        </div>
        <h2 className="text-2xl font-bold">Scaling your content engine...</h2>
      </div>
    </div>
  );

  // Step 4: Success
  if (step === 4) return (
    <div className={containerClass}>
      <div className={innerClass}>
        <h2 className="text-4xl font-black text-center">Engine Initialized 🚀</h2>
        <Card className="p-8 text-center space-y-4">
          <div className="w-16 h-16 bg-emerald-500/20 text-emerald-500 rounded-full flex items-center justify-center mx-auto">
            <Check size={32} />
          </div>
          <p className="text-xl font-bold italic">"Your story starts now, {form.name}."</p>
          <p className="text-zinc-500">Everything is optimized for the {form.niche.join(' & ')} niche on {form.platforms.join(', ')}.</p>
        </Card>
        <button onClick={() => onComplete(form)} className="w-full py-5 bg-purple-600 hover:bg-purple-500 text-white font-black text-xl rounded-2xl transition-all">Go to Dashboard</button>
      </div>
    </div>
  );

  return null;
}

