          setView('app');
          setOnboardingStep(0);
        }
      } else {
        setView('landing');
      }
    });
    return () => unsubscribe();
  }, []);

  const handleAuthSuccess = (user: FirebaseUser) => {
    // onAuthStateChanged takes care of the redirect
  };

  const handleLogout = async () => {
    await logoutUser();
    setUserProfile(null);
    setView('landing');
    setOnboardingStep(0);
  };

  const handleOnboardingComplete = async (profile: UserProfile) => {
    if (auth.currentUser) {
      await saveProfile(auth.currentUser.uid, profile);
      setUserProfile(profile);
      setOnboardingStep(5);
