function HookGeneratorView({ userProfile, onSaveIdea }: { userProfile: UserProfile | null, onSaveIdea: (idea: Omit<VideoIdea, 'id'>) => Promise<void> }) {
  const [topic, setTopic] = useState('');
  const [loading, setLoading] = useState(false);
  const [results, setResults] = useState<any[]>([]);
  const [savedStatus, setSavedStatus] = useState<Record<number, boolean>>({});

  const handleGenerate = async () => {
    if (!topic) return;
    setLoading(true);
    try {
      const niche = userProfile?.niche?.[0] || 'AI';
      const { results: hookResults } = await generateHooksWithSearch(topic, niche);
      setResults(hookResults);
      setSavedStatus({});
    } catch (e) { console.error(e); } finally { setLoading(false); }
  };

  const handleSave = async (hook: any, index: number) => {
    try {
      await onSaveIdea({
        title: topic || 'New Hook Idea',
        hook: hook.text,
        viralityScore: hook.viralityScore,
        status: 'idea'
      });
      setSavedStatus(prev => ({...prev, [index]: true}));
    } catch (e) {
      console.error(e);
    }
  };

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      <Card className="space-y-4">
        <h3 className="text-xl font-bold flex items-center gap-2"><Globe className="text-purple-400" size={20} /> Search-Grounded Hooks</h3>
