              disabled={savedStatus[i]}
              onClick={() => handleSave(h, i)}
              className={`w-full py-2 rounded-xl text-xs font-bold transition-all flex items-center justify-center gap-2 ${savedStatus[i] ? 'bg-emerald-500/10 text-emerald-500' : 'bg-zinc-800 hover:bg-zinc-700 text-zinc-300'}`}
