                </button>
              ))}
            </div>
            <button disabled={profile.platforms.length === 0} onClick={onNext} className="w-full py-4 bg-purple-600 rounded-2xl font-black disabled:opacity-50">Next</button>
          </div>
        );
      case 2:
        return (
