        <div className="p-8 max-w-7xl mx-auto">
          {userProfile && currentSubView === 'dashboard' && <DashboardView userProfile={userProfile} ideas={ideas} onDeleteIdea={handleDeleteIdea} onAction={setCurrentSubView} />}
